
import { useEffect, useState } from 'react';
import Navbar from '../../home/components/Navbar';
import Footer from '../../home/components/Footer';

export default function GalleryImagesPage() {
  const [scrolled, setScrolled] = useState(false);
  const [activeCategory, setActiveCategory] = useState('All');
  const [lightbox, setLightbox] = useState<string | null>(null);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const categories = ['All', 'Campus', 'Events', 'Sports', 'Labs', 'Convocation', 'Cultural'];

  const images = [
    { src: 'https://readdy.ai/api/search-image?query=engineering%20college%20campus%20aerial%20view%20green%20trees%20buildings%20Tamil%20Nadu%20India%20sunny%20day%20beautiful%20architecture&width=600&height=400&seq=gal-campus-1&orientation=landscape', category: 'Campus', caption: 'Main Campus Aerial View' },
    { src: 'https://readdy.ai/api/search-image?query=college%20annual%20day%20celebration%20stage%20performance%20students%20colorful%20lights%20auditorium%20India%20engineering%20college&width=600&height=400&seq=gal-event-1&orientation=landscape', category: 'Events', caption: 'Annual Day Celebration 2024' },
    { src: 'https://readdy.ai/api/search-image?query=students%20playing%20cricket%20college%20ground%20green%20field%20sunny%20day%20India%20sports%20event&width=600&height=400&seq=gal-sports-1&orientation=landscape', category: 'Sports', caption: 'Inter-College Cricket Tournament' },
    { src: 'https://readdy.ai/api/search-image?query=computer%20science%20laboratory%20students%20working%20on%20computers%20modern%20lab%20engineering%20college%20India&width=600&height=400&seq=gal-lab-1&orientation=landscape', category: 'Labs', caption: 'Computer Science Laboratory' },
    { src: 'https://readdy.ai/api/search-image?query=college%20convocation%20ceremony%20students%20graduation%20gown%20cap%20stage%20India%20engineering%20college%20proud%20moment&width=600&height=400&seq=gal-conv-1&orientation=landscape', category: 'Convocation', caption: 'Convocation Ceremony 2024' },
    { src: 'https://readdy.ai/api/search-image?query=college%20cultural%20fest%20students%20dancing%20traditional%20dress%20stage%20performance%20India%20colorful%20celebration&width=600&height=400&seq=gal-cult-1&orientation=landscape', category: 'Cultural', caption: 'Cultural Fest – Kaleidoscope 2024' },
    { src: 'https://readdy.ai/api/search-image?query=engineering%20college%20library%20interior%20books%20shelves%20students%20reading%20modern%20library%20India&width=600&height=400&seq=gal-campus-2&orientation=landscape', category: 'Campus', caption: 'Central Library' },
    { src: 'https://readdy.ai/api/search-image?query=college%20technical%20symposium%20students%20presenting%20project%20exhibition%20engineering%20India%20innovation%20fair&width=600&height=400&seq=gal-event-2&orientation=landscape', category: 'Events', caption: 'Technical Symposium 2024' },
    { src: 'https://readdy.ai/api/search-image?query=college%20basketball%20court%20students%20playing%20indoor%20sports%20hall%20India%20engineering%20college&width=600&height=400&seq=gal-sports-2&orientation=landscape', category: 'Sports', caption: 'Basketball Championship' },
    { src: 'https://readdy.ai/api/search-image?query=electronics%20laboratory%20students%20working%20circuit%20boards%20oscilloscope%20engineering%20college%20India%20modern%20equipment&width=600&height=400&seq=gal-lab-2&orientation=landscape', category: 'Labs', caption: 'Electronics & Communication Lab' },
    { src: 'https://readdy.ai/api/search-image?query=college%20hostel%20building%20exterior%20modern%20architecture%20green%20campus%20India%20residential%20block&width=600&height=400&seq=gal-campus-3&orientation=landscape', category: 'Campus', caption: 'Student Hostel Block' },
    { src: 'https://readdy.ai/api/search-image?query=college%20freshers%20day%20welcome%20party%20students%20celebration%20colorful%20decorations%20India%20engineering%20college&width=600&height=400&seq=gal-cult-2&orientation=landscape', category: 'Cultural', caption: "Freshers' Day 2024" },
  ];

  const filtered = activeCategory === 'All' ? images : images.filter(i => i.category === activeCategory);

  return (
    <div className="min-h-screen bg-white">
      <Navbar scrolled={scrolled} />
      <div className="pt-24">
        {/* Hero */}
        <div className="bg-gradient-to-r from-sky-700 to-sky-500 py-14 px-8">
          <div className="max-w-7xl mx-auto">
            <nav className="text-sm text-sky-200 mb-2">
              <span>Home</span> <span className="mx-2">/</span> <span>Gallery</span> <span className="mx-2">/</span>
              <span className="text-white font-medium">Images</span>
            </nav>
            <h1 className="text-4xl font-bold text-white">Photo Gallery</h1>
            <p className="text-sky-100 mt-2">Capturing memories, milestones, and moments at DMI Engineering College</p>
          </div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
          {/* Filter */}
          <div className="flex flex-wrap gap-2 mb-8 justify-center">
            {categories.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition-colors cursor-pointer whitespace-nowrap ${activeCategory === cat ? 'bg-sky-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-sky-50 hover:text-sky-600'}`}>
                {cat}
              </button>
            ))}
          </div>

          {/* Grid */}
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filtered.map((img, i) => (
              <div key={i} onClick={() => setLightbox(img.src)}
                className="group relative rounded-xl overflow-hidden shadow-sm hover:shadow-lg transition-shadow cursor-pointer">
                <div className="w-full h-52">
                  <img src={img.src} alt={img.caption} className="w-full h-full object-cover object-top group-hover:scale-105 transition-transform duration-300" />
                </div>
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/40 transition-colors flex items-end">
                  <p className="text-white text-sm font-medium px-3 py-2 translate-y-full group-hover:translate-y-0 transition-transform duration-300">{img.caption}</p>
                </div>
                <span className="absolute top-2 right-2 bg-sky-600 text-white text-xs px-2 py-0.5 rounded-full">{img.category}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div className="fixed inset-0 z-[200] bg-black/90 flex items-center justify-center p-4" onClick={() => setLightbox(null)}>
          <button className="absolute top-4 right-4 text-white text-3xl cursor-pointer w-10 h-10 flex items-center justify-center">
            <i className="ri-close-line"></i>
          </button>
          <img src={lightbox} alt="Gallery" className="max-w-full max-h-[90vh] rounded-lg object-contain" onClick={e => e.stopPropagation()} />
        </div>
      )}

      <Footer />
    </div>
  );
}
